import cirq


def encode_message(alice: cirq.Qid, bob: cirq.Qid, bits: str) -> cirq.Circuit:
    circuit = cirq.Circuit()

    circuit.append([
        cirq.H(alice),
        cirq.CNOT(alice, bob),
    ])

    if bits == '01':
        circuit.append(cirq.X(alice))
    elif bits == '10':
        circuit.append(cirq.Z(alice))
    elif bits == '11':
        circuit.append([cirq.Z(alice), cirq.X(alice)])

    circuit.append([
        cirq.CNOT(alice, bob),
        cirq.H(alice),
        cirq.measure(alice, bob, key='m'),
    ])
    return circuit

import cirq
import networkx as nx
import sympy as sp


def qaoa_layer(qubits: list[cirq.Qid], graph: nx.Graph, gamma: sp.Symbol, beta: sp.Symbol) -> cirq.Circuit:
    circuit = cirq.Circuit()

    for u, v in graph.edges:
        circuit.append(cirq.ZZ(qubits[u], qubits[v]) ** (gamma / sp.pi))

    for q in qubits:
        circuit.append(cirq.rx(2 * beta).on(q))

    return circuit

import cirq
import numpy as np


def qft_3(qubits: list[cirq.Qid], reverse: bool = True) -> cirq.Circuit:
    circuit = cirq.Circuit()
    n = 3
    for i in range(n):
        circuit.append(cirq.H(qubits[i]))
        for j in range(i + 1, n):
            theta = np.pi / (2 ** (j - i))
            circuit.append(cirq.CZ(qubits[j], qubits[i]) ** (theta / np.pi))
    if reverse:
        circuit.append(cirq.SWAP(qubits[0], qubits[2]))
    return circuit
